import{a as e,i as t,r as n,t as r}from"./app-CnBAqX6l.js";var i=JSON.parse(`{"path":"/%E5%A4%AE%E8%A7%86%E4%BC%9A%E8%AE%AE%E6%80%BB%E7%BB%93.html","title":"2026-03-02 中共中央政治局会议摘要","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1774836273000,"contributors":[{"name":"JiraiyaChen","username":"JiraiyaChen","email":"979526234@qq.com","commits":1,"url":"https://github.com/JiraiyaChen"}],"changelog":[{"hash":"7318efb2b3433787199988c8a1b814510fda6eb4","time":1774836273000,"email":"979526234@qq.com","author":"JiraiyaChen","message":"Add politics/时政 docs"}]},"filePathRelative":"央视会议总结.md"}`),a={name:`央视会议总结.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="_2026-03-02-中共中央政治局会议摘要" tabindex="-1"><a class="header-anchor" href="#_2026-03-02-中共中央政治局会议摘要"><span>2026-03-02 中共中央政治局会议摘要</span></a></h1><h3 id="会议背景" tabindex="-1"><a class="header-anchor" href="#会议背景"><span>会议背景</span></a></h3><p>中共中央政治局于2月27日召开会议，讨论国务院提交的《中华人民共和国国民经济和社会发展第十五个五年规划纲要草案》和《政府工作报告》稿。习近平总书记主持会议。</p><h2 id="核心内容" tabindex="-1"><a class="header-anchor" href="#核心内容"><span>核心内容</span></a></h2><h3 id="_1-十四五期间成就总结" tabindex="-1"><a class="header-anchor" href="#_1-十四五期间成就总结"><span>1. 十四五期间成就总结</span></a></h3><ul><li>面对世纪疫情和复杂环境，经济实力、科技实力显著提升。</li><li>中国式现代化取得新成就，全面建成社会主义现代化迈出坚实步伐。</li></ul><h3 id="_2-十五五规划重点" tabindex="-1"><a class="header-anchor" href="#_2-十五五规划重点"><span>2. 十五五规划重点</span></a></h3><ul><li>“十五五”时期是推动社会主义现代化的关键。</li><li>目标包括巩固优势、补短板、促高质量发展。</li><li>统筹“五位一体”布局和“四个全面”战略布局，全面贯彻新发展理念。</li></ul><h3 id="_3-当前政府工作方向" tabindex="-1"><a class="header-anchor" href="#_3-当前政府工作方向"><span>3. 当前政府工作方向</span></a></h3><ul><li>强调稳中求进，坚持经济建设为中心，推动高质量发展。</li><li>加强宏观经济政策前瞻性，持续扩大内需，推进科技自立。</li><li>关注重点领域风险，实施稳定就业、企业及市场的举措。</li></ul><h3 id="_4-促进改革开放与民生改善" tabindex="-1"><a class="header-anchor" href="#_4-促进改革开放与民生改善"><span>4. 促进改革开放与民生改善</span></a></h3><ul><li>推动重点领域改革及全国统一大市场建设。</li><li>深化乡村振兴，推进绿色发展与城镇协调。</li><li>大力保障民生，加强社会稳定与安全建设。</li></ul><h3 id="_5-政府建设与领导—新阶段" tabindex="-1"><a class="header-anchor" href="#_5-政府建设与领导—新阶段"><span>5. 政府建设与领导—新阶段</span></a></h3><ul><li>提倡改革创新驱动，加强政府自身能力建设。</li><li>树立正确政绩观，全面从严治党，落实中长期目标。</li></ul><p>文件内容反映了新阶段的顶层规划及实践方略，是未来重点聚焦领域的指导蓝图。</p>`,15)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};